class AuthenticatedSession {
    private final String sessionId;
    private final String userId;
    private final String samlSessionIndex;
    private final Instant expiryTime;
    private final Map<String, List<String>> userAttributes;
    private final Instant createdAt;
    
    public AuthenticatedSession(String sessionId, String userId, String samlSessionIndex,
                               Instant expiryTime, Map<String, List<String>> userAttributes) {
        this.sessionId = sessionId;
        this.userId = userId;
        this.samlSessionIndex = samlSessionIndex;
        this.expiryTime = expiryTime;
        this.userAttributes = Collections.unmodifiableMap(new HashMap<>(userAttributes));
        this.createdAt = Instant.now();
    }
    
    public String getSessionId() { return sessionId; }
    public String getUserId() { return userId; }
    public String getSamlSessionIndex() { return samlSessionIndex; }
    public Instant getExpiryTime() { return expiryTime; }
    public Map<String, List<String>> getUserAttributes() { return userAttributes; }
    public Instant getCreatedAt() { return createdAt; }
    
    public boolean isValid() {
        if (expiryTime == null) {
            return true;
        }
        return Instant.now().isBefore(expiryTime);
    }
    
    public String getAttributeValue(String attributeName) {
        List<String> values = userAttributes.get(attributeName);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }
    
    public List<String> getAttributeValues(String attributeName) {
        List<String> values = userAttributes.get(attributeName);
        return values != null ? new ArrayList<>(values) : Collections.emptyList();
    }
}

